export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i++
      continue
    }
    const key = arg.slice(2)
    if (key.includes('=')) {
      const [k, value] = key.split('=', 2)
      result[k] = value
      i++
      continue
    }
    result[key] = true
    i++
    // Check if next arg is a value (not a flag)
    if (i < argv.length && !argv[i].startsWith('--')) {
      result[key] = argv[i]
      i++
    }
  }
  return result
}

