      const key = arg.slice(2)
      if (i + 1 < argv.length) {
        const nextArg = argv[i + 1]
        if (!nextArg.startsWith('--')) {
          result[key] = nextArg
          i += 2
          continue
        }
      }
      result[key] = true
      i++
    } else if (arg.includes('=')) {
      const eqIndex = arg.indexOf('=')
      const key = arg.slice(2, eqIndex)
      result[key] = arg.slice(eqIndex + 1)
      i++
    } else {
      result._.push(arg)
      i++
    }
